// // Asynchronous reset D flip-flop. On each negative edge of the clock, if the reset signal is low, the output q is set to 1; otherwise, it takes the value of the input din.
module top_module(input clk,input rst,input din,output reg q);always@(posedge clk) 
  if(rst) 
  q <= 0; 
  else 
  q <= din; 
 endmodule
